# Dungeon Crawler
import random

def gen_room():
    w = random.randint(5, 15)
    h = random.randint(5, 15)
    return (w, h)

def gen_monster():
    hp = random.randint(10, 50)
    atk = random.randint(1, 10)
    return {"hp": hp, "atk": atk}

def gen_loot():
    gold = random.randint(1, 100)
    gems = random.randint(0, 5)
    return {"gold": gold, "gems": gems}

def gen_trap():
    damage = random.randint(5, 20)
    return {"dmg": damage}

def gen_floor(rooms=10):
    floor = []
    for i in range(rooms):
        floor.append(gen_room())
    return floor

def main():
    floors = [gen_floor() for _ in range(5)]
    print(f"{len(floors)} floors")

if __name__ == "__main__":
    main()
